export function isAllowedSpriteFolder(folder) {
    const n = (folder.name || '').trim().toLowerCase();
    const id = String(folder.id || '').trim().toLowerCase();
    // 固定 ID 的文件夹（Player、LuoTianhu）始终保留
    if (id === 'player' || id === 'luotianhu')
        return true;
    // 用户通过「新建角色」创建的文件夹（id 以 f_ 开头）
    if (id.startsWith('f_'))
        return true;
    // 合集文件夹：id 以 collection_ 开头，或名称以「合集」开头
    if (id.startsWith('collection_') || n.startsWith('合集'))
        return true;
    const allowed = ['user', '{{user}}', '主角', '玩家', '罗天虎'];
    return allowed.some(a => n === a.toLowerCase() || id === a.toLowerCase());
}
